const PORT = process.env.PORT || 3000;
const SERVER_SECRET = process.env.SERVER_SECRET || 'dev-secret-change-me';
const MAX_BODY_BYTES = 256 * 1024;

const db = {
  players: new Map(), // playerId -> { createdAt, lastSeenAt, levels: Map(levelId -> completion), pendingRewards: [], claimedRewardIds: Set() }
  rewardLedger: new Map(), // rewardId -> reward
};

function now() {
  return Date.now();
}

function sha256(input) {
  return crypto.createHash('sha256').update(input).digest('hex');
}

function hmac(payload) {
  return crypto.createHmac('sha256', SERVER_SECRET).update(payload).digest('hex');
}

function safeString(v, maxLen = 128) {
  if (typeof v !== 'string') return null;
  const s = v.trim();
  if (!s || s.length > maxLen) return null;
  return s;
}

function safeInt(v, min, max) {
  if (typeof v !== 'number' || !Number.isFinite(v)) return null;
  const n = Math.trunc(v);
  if (n < min || n > max) return null;
  return n;
}

function safeFloat(v, min, max) {
  if (typeof v !== 'number' || !Number.isFinite(v)) return null;
  if (v < min || v > max) return null;
  return v;
}

function getOrCreatePlayer(playerId) {
  let p = db.players.get(playerId);
  if (!p) {
    p = {
      createdAt: now(),
      lastSeenAt: now(),
      levels: new Map(),
      pendingRewards: [],
      claimedRewardIds: new Set(),
    };
    db.players.set(playerId, p);
  } else {
    p.lastSeenAt = now();
  }
  return p;
}

function computeRewardForCompletion({ levelId, score, timeMs }) {
  // Simple client-reported metric reward rules (casual puzzle game):
  // - base coins for completing a level
  // - bonus for high score tiers
  // - bonus for fast completion tiers
  // NOTE: This trusts client-reported metrics as requested; production should validate server-side/anti-cheat.
  const baseCoins = 20;

  let scoreBonus = 0;
  if (score >= 15000) scoreBonus = 60;
  else if (score >= 10000) scoreBonus = 40;
  else if (score >= 7000) scoreBonus = 25;
  else if (score >= 4000) scoreBonus = 12;

  let speedBonus = 0;
  if (timeMs <= 30000) speedBonus = 40;
  else if (timeMs <= 60000) speedBonus = 25;
  else if (timeMs <= 90000) speedBonus = 12;

  const stars = Math.max(
    1,
    Math.min(
      3,
      (score >= 12000 ? 3 : score >= 8000 ? 2 : 1) + (timeMs <= 45000 ? 1 : 0)
    )
  );

  const coins = baseCoins + scoreBonus + speedBonus;

  const reward = {
    coins,
    items: [],
    stars,
  };

  if (stars === 3) reward.items.push({ type: 'booster', id: 'hint', qty: 1 });
  if (coins >= 90) reward.items.push({ type: 'booster', id: 'shuffle', qty: 1 });

  return reward;
}

function makeRewardId(playerId, levelId, completionId) {
  const raw = `${playerId}|${levelId}|${completionId}|${SERVER_SECRET}`;
  return sha256(raw).slice(0, 32);
}

function normalizeClientCompletionId(v) {
  const s = safeString(v, 128);
  if (!s) return null;
  if (!/^[a-zA-Z0-9._-]+$/.test(s)) return null;
  return s;
}

function authMiddleware(req, res, next) {
  // Optional lightweight auth: X-Player-Id required.
  const playerId = safeString(req.header('X-Player-Id'), 64);
  if (!playerId) return res.status(401).json({ error: 'missing_player_id' });
  req.playerId = playerId;
  next();
}

