  const pending = p.pendingRewards.filter((r) => r.status === 'pending').map((r) => ({
    rewardId: r.rewardId,
    type: r.type,
    source: r.source,
    payload: r.payload,
    createdAt: r.createdAt,
  }));
  res.json({ ok: true, pendingRewards: pending });
