app.post('/v1/rewards/claim', authMiddleware, (req, res) => {
  const rewardId = safeString(req.body?.rewardId, 64);
  if (!rewardId) return res.status(400).json({ error: 'invalid_reward_id' });

  const p = getOrCreatePlayer(req.playerId);
  const reward = db.rewardLedger.get(rewardId);
  if (!reward) return res.status(404).json({ error: 'reward_not_found' });
  if (reward.playerId !== req.playerId) return res.status(403).json({ error: 'reward_not_owned' });

  if (p.claimedRewardIds.has(rewardId) || reward.status === 'claimed') {
    return res.json({ ok: true, rewardId, claimed: true, deduped: true, payload: reward.payload });
  }

  // Mark claimed
  reward.status = 'claimed';
  reward.claimedAt = now();
  p.claimedRewardIds.add(rewardId);

  // Remove from pending list (keep ledger)
  for (const r of p.pendingRewards) {
    if (r.rewardId === rewardId) r.status = 'claimed';
  }
  p.pendingRewards = p.pendingRewards.filter((r) => r.status === 'pending');

  // In a real game you'd also apply to a player inventory/currency store here.
  res.json({ ok: true, rewardId, claimed: true, payload: reward.payload });
});

app.post('/v1/rewards/claim-batch', authMiddleware, (req, res) => {
  const ids = Array.isArray(req.body?.rewardIds) ? req.body.rewardIds : null;
  if (!ids || ids.length === 0 || ids.length > 100) return res.status(400).json({ error: 'invalid_reward_ids' });

  const p = getOrCreatePlayer(req.playerId);
  const results = [];

  for (const id of ids) {
    const rewardId = safeString(id, 64);
    if (!rewardId) {
      results.push({ rewardId: id, ok: false, error: 'invalid_reward_id' });
      continue;
    }
    const reward = db.rewardLedger.get(rewardId);
    if (!reward) {
      results.push({ rewardId, ok: false, error: 'reward_not_found' });
      continue;
    }
    if (reward.playerId !== req.playerId) {
      results.push({ rewardId, ok: false, error: 'reward_not_owned' });
      continue;
    }
    if (p.claimedRewardIds.has(rewardId) || reward.status === 'claimed') {
      results.push({ rewardId, ok: true, claimed: true, deduped: true, payload: reward.payload });
      continue;
    }

    reward.status = 'claimed';
    reward.claimedAt = now();
    p.claimedRewardIds.add(rewardId);
    for (const r of p.pendingRewards) {
      if (r.rewardId === rewardId) r.status = 'claimed';
    }
    results.push({ rewardId, ok: true, claimed: true, payload: reward.payload });
  }

  p.pendingRewards = p.pendingRewards.filter((r) => r.status === 'pending');

  res.json({ ok: true, results });
});

